\"currentColor\\" stroke-width=\\"1.3\\" stroke-linecap=\\"round\\"\\r\\n                        stroke-linejoin=\\"round\\" />\\r\\n                </svg>\\r\\n                VISIT WEBSITE</a>\\r\\n        </div>\\r\\n\\r\\n        <div class=\\"link-card\\">\\r\\n            <span class=\\"link-text\\">DigiLocker</span>\\r\\n            <a href=\\"https://www.digilocker.gov.in/\\" class=\\"visit-btn\\"><i class=\\"fas fa-external-link-alt\\"></i>\\r\\n                <svg width=\\"14\\" height=\\"14\\" viewBox=\\"0 0 14 14\\" fill=\\"none\\">\\r\\n                    <path d=\\"M6 2H2a1 1 0 00-1 1v9a1 1 0 001 1h9a1 1 0 001-1V8\\" stroke=\\"currentColor\\" stroke-width=\\"1.3\\"\\r\\n                        stroke-linecap=\\"round\\" />\\r\\n                    <path d=\\"M9 1h4v4M13 1L7 7\\" stroke=\\"currentColor\\" stroke-width=\\"1.3\\" stroke-linecap=\\"round\\"\\r\\n                        stroke-linejoin=\\"round\\" />\\r\\n                </svg>\\r\\n                VISIT WEBSITE</a>\\r\\n        </div>\\r\\n    </div>\\r\\n</div>","css":"* {\\r\\n    margin: 0;\\r\\n    padding: 0;\\r\\n    box-sizing: border-box;\\r\\n    font-family: \'Segoe UI\', Tahoma, Geneva, Verdana, sans-serif;\\r\\n}\\r\\n\\r\\nbody {\\r\\n    background-color: #fcfcfc; /* Light background as seen in image */\\r\\n    display: flex;\\r\\n    justify-content: center;\\r\\n    padding: 40px 20px;\\r\\n}\\r\\n\\r\\n.container {\\r\\n    width: 100%;\\r\\n    max-width: 900px;\\r\\n}\\r\\n\\r\\n/* Search Bar Styling */\\r\\n.search-container {\\r\\n    position: relative;\\r\\n    margin-bottom: 25px;\\r\\n}\\r\\n\\r\\n.search-icon {\\r\\n    position: absolute;\\r\\n    left: 15px;\\r\\n    top: 50%;\\r\\n    transform: translateY(-50%);\\r\\n    color: #4a7c92;\\r\\n    font-size: 18px;\\r\\n}\\r\\n\\r\\n.search-container input {\\r\\n    width: 100%;\\r\\n    padding: 12px 12px 12px 45px;\\r\\n    border: 1.5px solid #4a74d4; /* Blue border */\\r\\n    border-radius: 6px;\\r\\n    font-size: 16px;\\r\\n    color: #555;\\r\\n    outline: none;\\r\\n}\\r\\n\\r\\n/* Links Wrapper */\\r\\n.links-wrapper {\\r\\n    display: flex;\\r\\n    flex-direction: column;\\r\\n    gap: 12px; /* Spacing between cards */\\r\\n}\\r\\n\\r\\n/* Individual Link Card */\\r\\n.link-card {\\r\\n    background: #fff;\\r\\n    border: 1px solid #e0e0e0;\\r\\n    border-radius: 8px;\\r\\n    display: flex;\\r\\n    justify-content: space-between;\\r\\n    align-items: center;\\r\\n    padding: 10px 15px;\\r\\n    transition: box-shadow 0.3s ease;\\r\\n}\\r\\n\\r\\n.link-card:hover {\\r\\n    box-shadow: 0 2px 8px rgba(0,0,0,0.05);\\r\\n}\\r\\n\\r\\n.link-text {\\r\\n    font-size: 16px;\\r\\n    color: #333;\\r\\n    font-weight: 500;\\r\\n}\\r\\n\\r\\n/* Visit Website Button */\\r\\n.visit-btn {\\r\\n    background-color: #dbe4ff; /* Very light blue background */\\r\\n    color: #2c54c1; /* Strong blue text */\\r\\n    text-decoration: none;\\r\\n    font-size: 12px;\\r\\n    font-weight: bold;\\r\\n    padding: 10px 20px;\\r\\n    border-radius: 6px;\\r\\n    display: flex;\\r\\n    align-items: center;\\r\\n    gap: 8px;\\r\\n    transition: background 0.3s ease;\\r\\n}\\r\\n\\r\\n.visit-btn:hover {\\r\\n    background-color: #c9d6ff;\\r\\n}\\r\\n\\r\\n.visit-btn i {\\r\\n    font-size: 14px;\\r\\n}\\r\\n\\r\\n/* Responsive adjustment */\\r\\n@media (max-width: 600px) {\\r\\n    .link-card {\\r\\n        flex-direction: column;\\r\\n        align-items: flex-start;\\r\\n        gap: 10px;\\r\\n    }\\r\\n    .visit-btn {\\r\\n        width: 100%;\\r\\n        justify-content: center;\\r\\n    }\\r\\n}","js":""}', 0, 1, '2026-04-29 10:29:58', '2026-04-29 12:35:15', NULL),
	(29, 'Cabinet Secretary', '/cabinet-secretariat/cabinet-secretary', NULL, NULL, NULL, NULL, NULL, '{"html":"<!DOCTYPE html>\\r\\n<html lang=\\"en\\">\\r\\n<head>\\r\\n  <meta charset=\\"UTF-8\\">\\r\\n  <title>Profile</title>\\r\\n  <link rel=\\"stylesheet\\" href=\\"style.css\\">\\r\\n</head>\\r\\n<body>\\r\\n\\r\\n<div class=\\"container\\">\\r\\n  \\r\\n  <div class=\\"profile-card\\">\\r\\n    \\r\\n    <!-- Left Image -->\\r\\n    <div class=\\"profile-image\\">\\r\\n      <img src=\\"/report_document/files-1780916831522-830222981.jpg\\" alt=\\"Profile Photo\\">\\r\\n    </div>\\r\\n\\r\\n    <!-- Right Content -->\\r\\n    <div class=\\"profile-content\\">\\r\\n     <h2>Dr. T. V. Somanathan</h2><h3><strong>CABINET SECRETARY</strong></h3><p>Dr. T. V. Somanathan is a distinguished Indian Administrative Service officer of the 1987 batch, Tamil Nadu cadre, currently serving as the <strong>Cabinet Secretary of India</strong> since <strong>30 August 2024</strong>. With an illustrious career spanning over three decades, he has held several key positions at both national and international levels.</p><p>Prior to his appointment as Cabinet Secretary, Dr. Somanathan served as the <strong>Finance Secretary of India</strong>, heading the <strong>Department of Expenditure</strong>. His earlier roles at the Centre include serving as <strong>Additional Secretary</strong> and <strong>Joint Secretary in the Prime Ministerâ€™s Office (PMO)</strong>, where he played a pivotal role in various governance and policy initiatives.</p><p>Internationally, Dr. Somanathan served as <strong>Director, Corporate Affairs</strong> at the <strong>World Bank Group</strong> in Washington, D.C., having initially joined through its prestigious <strong>Young Professionals Program</strong>. His expertise in public finance and economic policy has been widely recognized both in India and abroad.</p><p>In the Ministry of Corporate Affairs, he contributed significantly as <strong>Joint Secretary</strong>, focusing on reforms and regulatory frameworks that enhanced corporate governance.</p><h3><strong>Educational Qualifications</strong></h3><ul><li><strong>Ph.D. in Economics</strong>, University of Calcutta</li><li><strong>Executive Development Program</strong>, Harvard Business School</li><li><strong>Chartered Accountant (CA)</strong></li><li><strong>Cost Accountant (CMA)</strong></li><li><strong>Company Secretary (CS)</strong></li></ul><p>Dr. Somanathan combines deep academic insight with practical administrative experience, making him one of Indiaâ€™s most respected civil servants. His professional journey reflects a commitment to excellence, integrity, and nation-building.</p>\\r\\n\\r\\n    </div>\\r\\n\\r\\n  </div>\\r\\n\\r\\n</div>\\r\\n\\r\\n</body>\\r\\n</html>","css":"body {\\r\\n  margin: 0;\\r\\n  font-family: Arial, sans-serif;\\r\\n}\\r\\n\\r\\n.container {\\r\\n  display: flex;\\r\\n  justify-content: center;\\r\\n  padding: 40px;\\r\\n}\\r\\n\\r\\n.profile-card {\\r\\n  display: flex;\\r\\n  gap: 40px;\\r\\n  padding: 30px;\\r\\n  max-width: 1100px;\\r\\n  width: 100%;\\r\\n}\\r\\n\\r\\n.profile-image img {\\r\\n  width: 280px;\\r\\n  height: auto;\\r\\n  object-fit: cover;\\r\\n}\\r\\n\\r\\n.profile-content {\\r\\n  flex: 1;\\r\\n}\\r\\n\\r\\n.profile-content h1 {\\r\\n  margin: 0;\\r\\n  font-size: 24px;\\r\\n  color: #1a2a5a;\\r\\n}\\r\\n\\r\\n.profile-content h3 {\\r\\n  margin-top: 5px;\\r\\n  font-size: 14px;\\r\\n  letter-spacing: 1px;\\r\\n}\\r\\n\\r\\n.profile-content p {\\r\\n  font-size: 14px;\\r\\n  line-height: 1.6;\\r\\n  color: #333;\\r\\n}\\r\\n\\r\\n.profile-content h4 {\\r\\n  margin-top: 20px;\\r\\n  font-size: 16px;\\r\\n}\\r\\n\\r\\n.profile-content ul {\\r\\n  padding-left: 20px;\\r\\n}\\r\\n\\r\\n.profile-content ul li {\\r\\n  margin-bottom: 8px;\\r\\n  font-size: 14px;\\r\\n}","js":""}', 0, 1, '2026-05-05 10:29:48', '2026-06-08 11:07:25', NULL),
